import '../lib/form_encoder.dart';

void expectEqual(Object? actual, Object? expected) {
  if (actual != expected) {
    throw StateError('Expected $expected, got $actual');
  }
}

void main() {
  expectEqual(encodeForm(<String, String>{'query': 'red blue'}), 'query=red+blue');
  expectEqual(encodeForm(<String, String>{'tag': 'a+b'}), 'tag=a%2Bb');
}
